{"file_text": "@page "/chat"
@layout ChatLayout
@rendermode InteractiveServer
@using sv_9a37e4698c4442d9a39bdaf80bc8e27c.Models
@using sv_9a37e4698c4442d9a39bdaf80bc8e27c.Services
@inject IChatService ChatService
@inject IJSRuntime JS

<PageTitle>Chat</PageTitle>

<div class="chat-container">
    <ChannelSidebar Channels="_channels"
                    ActiveChannelId="_activeChannelId"
                    OnChannelSelected="SelectChannel" />

    <div class="main-panel @(_isThreadOpen ? "with-thread" : "")">
        @if (_activeChannel is not null)
        {
            <MessageArea ChannelName="@_activeChannel.Name"
                         ChannelDescription="@_activeChannel.Description"
                         Messages="_messages"
                         ThreadReplyCounts="_threadReplyCounts"
                         IsLoadingMore="_isLoadingMore"
                         OnLoadOlderMessages="LoadOlderMessages"
                         OnSendMessage="SendMessage"
                         OnOpenThread="OpenThread"
                         OnReactToMessage="ReactToMessage" />
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </div>

    @if (_isThreadOpen && _threadRootMessage is not null)
    {
        <ThreadPanel RootMessage="_threadRootMessage"
                     ThreadMessages="_threadMessages"
                     OnClose="CloseThread"
                     OnSendReply="SendThreadReply" />
    }
</div>

@code {
    private List<Channel> _channels = [];
    private int _activeChannelId;
    private Channel? _activeChannel;
    private List<Message> _messages = [];
    private Dictionary<int, int> _threadReplyCounts = [];
    private bool _isLoadingMore;

    private bool _isThreadOpen;
    private Message? _threadRootMessage;
    private List<Message> _threadMessages = [];

    private const int PageSize = 30;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
        {
            await SelectChannel(_channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        _activeChannelId = channelId;
        _activeChannel = _channels.FirstOrDefault(c => c.Id == channelId);
        _messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        _isThreadOpen = false;
        _threadRootMessage = null;
        _threadMessages = [];
        await ChatService.MarkChannelReadAsync(channelId);
        ComputeThreadReplyCounts();
    }

    private async Task LoadOlderMessages()
    {
        if (_isLoadingMore || _activeChannel is null) return;
        _isLoadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(_activeChannelId, _messages.Count, PageSize);
        if (older.Count > 0)
        {
            _messages.InsertRange(0, older);
            ComputeThreadReplyCounts();
        }
        _isLoadingMore = false;
    }

    private async Task SendMessage(string content)
    {
        if (_activeChannel is null) return;
        var msg = await ChatService.SendMessageAsync(_activeChannelId, content, null);
        _messages.Add(msg);
    }

    private async Task OpenThread(int messageId)
    {
        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == messageId);
        if (_threadRootMessage is null) return;

        _threadMessages = await ChatService.GetThreadAsync(messageId);
        _isThreadOpen = true;
    }

    private void CloseThread()
    {
        _isThreadOpen = false;
        _threadRootMessage = null;
        _threadMessages = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (_threadRootMessage is null || _activeChannel is null) return;
        var reply = await ChatService.SendMessageAsync(_activeChannelId, content, _threadRootMessage.Id);
        _threadMessages.Add(reply);

        // Update reply count
        _threadReplyCounts[_threadRootMessage.Id] = _threadMessages.Count;
    }

    private async Task ReactToMessage((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Refresh the specific message's reactions locally
        var msg = _messages.FirstOrDefault(m => m.Id == args.MessageId);
        if (msg is not null)
        {
            var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == args.Emoji);
            if (existing is not null)
            {
                existing.Users.Add("You");
            }
            else
            {
                msg.Reactions.Add(new Reaction(args.Emoji, ["You"]));
            }
        }
    }

    private void ComputeThreadReplyCounts()
    {
        _threadReplyCounts = _messages
            .Where(m => m.ReplyToId is not null)
            .GroupBy(m => m.ReplyToId!.Value)
            .ToDictionary(g => g.Key, g => g.Count());
    }
}
